// src/utils/fixUrl.js

export const BASE_URL = 'http://localhost:3333';

// Функция, которая делает URL абсолютным, если он относительный
export const getImageUrl = (url) => {
  if (!url) return ''; // Или путь к картинке-заглушке
  if (url.startsWith('http')) {
    return url; // Если это уже полный URL (https://...), возвращаем его как есть
  }
  return `${BASE_URL}${url}`; // Добавляем базовый URL для относительных путей
};
